class AutocompleteSystem:
    def __init__(self, sentences, times):
        self.trie = {}; self.curr = ""; self.counts = collections.Counter()
        for s, t in zip(sentences, times): self.add(s, t)
    def add(self, s, t): self.counts[s] += t
    def input(self, c):
        if c == "#": self.add(self.curr, 1); self.curr = ""; return []
        self.curr += c
        res = [(self.counts[s], s) for s in self.counts if s.startswith(self.curr)]
        return [s for c, s in sorted(res, key=lambda x: (-x[0], x[1]))[:3]]

